// =============================================
// NimaView Engine - Remix Advanced Gado
// Version 1.0.0 - By NimaView
// =============================================

const NimaView = {
    version: "1.0.0",
    canvas: null,
    ctx: null,
    camera: { x: 0, y: 0, z: 380, rotX: 0.35, rotY: 0.45, fov: 580 },
    objects: [],
    particles: [],
    lights: [],
    keys: {},
    mouse: { x: 0, y: 0, down: false, prevX: 0, prevY: 0 },
    scene: 'main',
    score: 0,
    lives: 3,
    gameState: 'playing',
    audioCtx: null,
    isInitialized: false,

    // ==========================================
    // CORE INITIALIZATION
    // ==========================================
    init(canvasId = 'game') {
        if (this.isInitialized) return;
        
        this.canvas = document.getElementById(canvasId);
        if (!this.canvas) {
            this.canvas = document.createElement('canvas');
            this.canvas.width = 1024;
            this.canvas.height = 680;
            document.body.appendChild(this.canvas);
        }
        this.ctx = this.canvas.getContext('2d');
        
        // Setup audio context
        try {
            this.audioCtx = new (window.AudioContext || window.webkitAudioContext)();
        } catch(e) {
            console.warn('Web Audio API not supported');
        }

        this.setupControls();
        this.createDefaultScene();
        this.isInitialized = true;
        this.gameLoop();
        
        console.log(`%c🚀 NimaView Engine v${this.version} Loaded!`, 'color:#0ff;font-size:20px;font-weight:bold;');
        console.log('%c✨ Advanced features ready: 3D Objects, Particles, Physics, Sound, UI', 'color:#afa;font-size:14px;');
        console.log('%c🎮 Use WASD to move, Mouse to rotate, Space for boom!', 'color:#ffa;font-size:14px;');
        return this;
    },

    // ==========================================
    // CONTROLS
    // ==========================================
    setupControls() {
        // Keyboard
        window.addEventListener('keydown', e => {
            this.keys[e.key.toLowerCase()] = true;
            if (e.key === ' ') {
                e.preventDefault();
                this.spawnExplosion(this.camera.x, this.camera.y, 0);
                this.playSound(300, 0.3);
            }
        });
        window.addEventListener('keyup', e => {
            this.keys[e.key.toLowerCase()] = false;
        });

        // Mouse
        this.canvas.addEventListener('mousedown', (e) => {
            this.mouse.down = true;
            this.mouse.prevX = e.clientX;
            this.mouse.prevY = e.clientY;
        });
        window.addEventListener('mouseup', () => {
            this.mouse.down = false;
        });
        this.canvas.addEventListener('mousemove', (e) => {
            const rect = this.canvas.getBoundingClientRect();
            this.mouse.x = e.clientX - rect.left;
            this.mouse.y = e.clientY - rect.top;
            
            if (this.mouse.down) {
                const dx = e.clientX - this.mouse.prevX;
                const dy = e.clientY - this.mouse.prevY;
                this.camera.rotY += dx * 0.005;
                this.camera.rotX += dy * 0.005;
                this.camera.rotX = Math.max(-1.2, Math.min(1.2, this.camera.rotX));
                this.mouse.prevX = e.clientX;
                this.mouse.prevY = e.clientY;
            }
        });
    },

    // ==========================================
    // PROJECTION SYSTEM
    // ==========================================
    project(x, y, z) {
        const { fov, z: camZ } = this.camera;
        // Apply camera rotation (simplified)
        const dist = fov / (z + camZ);
        return {
            x: this.canvas.width / 2 + (x - this.camera.x) * dist,
            y: this.canvas.height / 2 + (y - this.camera.y) * dist,
            scale: dist,
            depth: z + camZ
        };
    },

    // ==========================================
    // OBJECT SYSTEM
    // ==========================================
    createObject(type, props = {}) {
        const obj = {
            id: Date.now() + Math.random() * 1000,
            type: type || 'cube',
            x: props.x || 0,
            y: props.y || 0,
            z: props.z || 0,
            rotX: props.rotX || 0,
            rotY: props.rotY || 0,
            rotZ: props.rotZ || 0,
            size: props.size || 60,
            color: props.color || '#00ffff',
            wireframe: props.wireframe || false,
            active: true,
            velocity: { x: 0, y: 0, z: 0 },
            gravity: props.gravity || false,
            mass: props.mass || 1,
            onCollide: props.onCollide || null,
        };
        this.objects.push(obj);
        return obj;
    },

    removeObject(id) {
        this.objects = this.objects.filter(o => o.id !== id);
    },

    // ==========================================
    // PARTICLE SYSTEM
    // ==========================================
    spawnExplosion(x = 0, y = 0, z = 0, count = 200) {
        const colors = ['#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff', '#ff6bff', '#ff9f43'];
        for (let i = 0; i < count; i++) {
            this.particles.push({
                x: x + (Math.random() - 0.5) * 20,
                y: y + (Math.random() - 0.5) * 20,
                z: z + (Math.random() - 0.5) * 20,
                vx: (Math.random() - 0.5) * 25,
                vy: (Math.random() - 0.5) * 25 - 10,
                vz: (Math.random() - 0.5) * 25,
                life: 60 + Math.random() * 60,
                maxLife: 120,
                size: 3 + Math.random() * 10,
                color: colors[Math.floor(Math.random() * colors.length)],
                gravity: 0.5 + Math.random() * 0.5,
                type: 'explosion'
            });
        }
    },

    spawnParticles(x, y, z, config = {}) {
        const count = config.count || 50;
        const colors = config.colors || ['#ffffff'];
        for (let i = 0; i < count; i++) {
            this.particles.push({
                x: x + (Math.random() - 0.5) * (config.spread || 10),
                y: y + (Math.random() - 0.5) * (config.spread || 10),
                z: z + (Math.random() - 0.5) * (config.spread || 10),
                vx: (Math.random() - 0.5) * (config.speed || 5),
                vy: (Math.random() - 0.5) * (config.speed || 5) - (config.downward || 0),
                vz: (Math.random() - 0.5) * (config.speed || 5),
                life: config.life || 30 + Math.random() * 30,
                maxLife: config.maxLife || 60,
                size: config.size || 2 + Math.random() * 6,
                color: colors[Math.floor(Math.random() * colors.length)],
                gravity: config.gravity || 0.2,
                type: config.type || 'custom'
            });
        }
    },

    // ==========================================
    // AUDIO SYSTEM
    // ==========================================
    playSound(freq = 440, duration = 0.2, type = 'sine') {
        if (!this.audioCtx) return;
        try {
            const osc = this.audioCtx.createOscillator();
            const gain = this.audioCtx.createGain();
            osc.type = type;
            osc.frequency.value = freq;
            gain.gain.setValueAtTime(0.15, this.audioCtx.currentTime);
            gain.gain.exponentialRampToValueAtTime(0.001, this.audioCtx.currentTime + duration);
            osc.connect(gain);
            gain.connect(this.audioCtx.destination);
            osc.start();
            osc.stop(this.audioCtx.currentTime + duration);
        } catch(e) {}
    },

    // ==========================================
    // PHYSICS
    // ==========================================
    updatePhysics() {
        const groundY = 80;
        for (const obj of this.objects) {
            if (!obj.gravity) continue;
            obj.velocity.y -= 1.2 * obj.mass;
            obj.y += obj.velocity.y * 0.1;
            obj.x += obj.velocity.x * 0.1;
            obj.z += obj.velocity.z * 0.1;

            // Ground collision
            if (obj.y < groundY) {
                obj.y = groundY;
                if (obj.velocity.y < 0) {
                    obj.velocity.y *= -0.4;
                }
                if (Math.abs(obj.velocity.y) < 0.5) obj.velocity.y = 0;
            }

            // Simple bounce on walls (boundary)
            const halfSize = obj.size / 2;
            if (obj.x < -150 + halfSize) { obj.x = -150 + halfSize; obj.velocity.x *= -0.5; }
            if (obj.x > 150 - halfSize) { obj.x = 150 - halfSize; obj.velocity.x *= -0.5; }
            if (obj.z < -150 + halfSize) { obj.z = -150 + halfSize; obj.velocity.z *= -0.5; }
            if (obj.z > 150 - halfSize) { obj.z = 150 - halfSize; obj.velocity.z *= -0.5; }
        }
    },

    // ==========================================
    // COLLISION DETECTION
    // ==========================================
    checkCollisions() {
        for (let i = 0; i < this.objects.length; i++) {
            for (let j = i + 1; j < this.objects.length; j++) {
                const a = this.objects[i];
                const b = this.objects[j];
                if (!a.active || !b.active) continue;
                
                const dx = a.x - b.x;
                const dy = a.y - b.y;
                const dz = a.z - b.z;
                const dist = Math.sqrt(dx*dx + dy*dy + dz*dz);
                const threshold = (a.size + b.size) / 2;
                
                if (dist < threshold) {
                    // Simple push apart
                    const angle = Math.atan2(dz, dx);
                    const force = (threshold - dist) * 0.1;
                    a.x += Math.cos(angle) * force;
                    a.z += Math.sin(angle) * force;
                    b.x -= Math.cos(angle) * force;
                    b.z -= Math.sin(angle) * force;
                    
                    if (a.onCollide) a.onCollide(b);
                    if (b.onCollide) b.onCollide(a);
                }
            }
        }
    },

    // ==========================================
    // SCENE MANAGEMENT
    // ==========================================
    createDefaultScene() {
        // Ground grid
        for (let i = -5; i <= 5; i++) {
            this.objects.push({
                id: 'grid_' + i,
                type: 'line',
                x1: i * 50, y1: 0, z1: -250,
                x2: i * 50, y2: 0, z2: 250,
                color: '#335577',
                active: true,
            });
            this.objects.push({
                id: 'gridz_' + i,
                type: 'line',
                x1: -250, y1: 0, z1: i * 50,
                x2: 250, y2: 0, z2: i * 50,
                color: '#335577',
                active: true,
            });
        }

        // Main cube
        this.createObject('cube', {
            x: 0, y: 40, z: 0,
            color: '#00ffff',
            size: 70,
            rotY: 0.5,
            gravity: true,
        });

        // Floating objects
        const colors = ['#ff6b6b', '#ffd93d', '#6bcb77', '#4d96ff', '#ff6bff'];
        for (let i = 0; i < 5; i++) {
            const obj = this.createObject(i % 2 === 0 ? 'sphere' : 'pyramid', {
                x: (Math.random() - 0.5) * 300,
                y: 60 + Math.random() * 80,
                z: (Math.random() - 0.5) * 300,
                color: colors[i],
                size: 25 + Math.random() * 20,
                rotY: Math.random() * 6,
                gravity: false,
            });
            // Store floating animation data
            obj.floatOffset = Math.random() * 100;
            obj.floatSpeed = 0.8 + Math.random() * 0.5;
        }
    },

    // ==========================================
    // RENDER SYSTEM
    // ==========================================
    drawObject3D(obj) {
        if (obj.type === 'line') {
            this.ctx.beginPath();
            const p1 = this.project(obj.x1, obj.y1, obj.z1);
            const p2 = this.project(obj.x2, obj.y2, obj.z2);
            this.ctx.moveTo(p1.x, p1.y);
            this.ctx.lineTo(p2.x, p2.y);
            this.ctx.strokeStyle = obj.color || '#335577';
            this.ctx.lineWidth = 1.5;
            this.ctx.stroke();
            return;
        }

        const size = obj.size || 60;
        const half = size / 2;
        let points = [];
        const { rotX, rotY, rotZ } = obj;

        // Generate 8 corners of a cube
        for (let x = -1; x <= 1; x += 2) {
            for (let y = -1; y <= 1; y += 2) {
                for (let z = -1; z <= 1; z += 2) {
                    let px = x * half;
                    let py = y * half;
                    let pz = z * half;

                    // Rotation X
                    let rx = py * Math.cos(rotX) - pz * Math.sin(rotX);
                    let rz = py * Math.sin(rotX) + pz * Math.cos(rotX);
                    py = rx; pz = rz;

                    // Rotation Y
                    let ry = px * Math.cos(rotY) - pz * Math.sin(rotY);
                    pz = px * Math.sin(rotY) + pz * Math.cos(rotY);
                    px = ry;

                    // Rotation Z
                    let rz2 = px * Math.cos(rotZ) - py * Math.sin(rotZ);
                    let ry2 = px * Math.sin(rotZ) + py * Math.cos(rotZ);
                    px = rz2; py = ry2;

                    // Scale with shape (sphere, pyramid, etc.)
                    let shapeScale = 1;
                    if (obj.type === 'sphere') {
                        shapeScale = 0.7 + 0.3 * (x*x + y*y + z*z) / 3;
                    } else if (obj.type === 'pyramid') {
                        shapeScale = 0.6 + 0.4 * Math.abs(z);
                    }
                    px *= shapeScale;
                    py *= shapeScale;
                    pz *= shapeScale;

                    points.push(this.project(px + obj.x, py + obj.y, pz + obj.z));
                }
            }
        }

        // Draw faces or edges
        const edges = [
            [0,1],[1,3],[3,2],[2,0],
            [4,5],[5,7],[7,6],[6,4],
            [0,4],[1,5],[2,6],[3,7]
        ];

        // Apply lighting based on depth
        const avgDepth = points.reduce((sum, p) => sum + p.depth, 0) / points.length;
        const brightness = Math.min(1, Math.max(0.3, 1 - (avgDepth - 300) / 500));

        if (obj.wireframe) {
            this.ctx.strokeStyle = obj.color || '#00ffff';
            this.ctx.lineWidth = 2;
            edges.forEach(([a, b]) => {
                this.ctx.beginPath();
                this.ctx.moveTo(points[a].x, points[a].y);
                this.ctx.lineTo(points[b].x, points[b].y);
                this.ctx.stroke();
            });
        } else {
            // Fill with color and opacity
            const color = obj.color || '#00ffff';
            this.ctx.fillStyle = color;
            this.ctx.globalAlpha = 0.3 + brightness * 0.5;
            
            // Draw as filled shape (simplified)
            this.ctx.beginPath();
            const center = this.project(obj.x, obj.y, obj.z);
            const radius = half * 1.2 * center.scale;
            
            // Draw a circle with gradient for sphere-like effect
            if (obj.type === 'sphere') {
                const grad = this.ctx.createRadialGradient(
                    center.x - radius * 0.2, center.y - radius * 0.3, radius * 0.1,
                    center.x, center.y, radius
                );
                grad.addColorStop(0, '#ffffff');
                grad.addColorStop(0.3, color);
                grad.addColorStop(1, this.darkenColor(color, 0.5));
                this.ctx.fillStyle = grad;
                this.ctx.beginPath();
                this.ctx.arc(center.x, center.y, radius, 0, Math.PI * 2);
                this.ctx.fill();
            } else {
                // For cube/pyramid: draw edges with glow
                this.ctx.strokeStyle = color;
                this.ctx.lineWidth = 1.5 + brightness * 2;
                this.ctx.shadowColor = color;
                this.ctx.shadowBlur = 15;
                edges.forEach(([a, b]) => {
                    this.ctx.beginPath();
                    this.ctx.moveTo(points[a].x, points[a].y);
                    this.ctx.lineTo(points[b].x, points[b].y);
                    this.ctx.stroke();
                });
                this.ctx.shadowBlur = 0;
            }
            this.ctx.globalAlpha = 1;
        }
    },

    darkenColor(color, factor) {
        let r = parseInt(color.slice(1,2), 16) * 17 || 0;
        let g = parseInt(color.slice(2,3), 16) * 17 || 0;
        let b = parseInt(color.slice(3,4), 16) * 17 || 0;
        if (color.length === 7) {
            r = parseInt(color.slice(1,3), 16);
            g = parseInt(color.slice(3,5), 16);
            b = parseInt(color.slice(5,7), 16);
        }
        r = Math.floor(r * factor);
        g = Math.floor(g * factor);
        b = Math.floor(b * factor);
        return `rgb(${r},${g},${b})`;
    },

    // ==========================================
    // UI/HUD SYSTEM
    // ==========================================
    drawText(text, x, y, color = '#ffffff', size = 20, align = 'left') {
        this.ctx.fillStyle = color;
        this.ctx.font = `bold ${size}px Arial, sans-serif`;
        this.ctx.textAlign = align;
        this.ctx.shadowColor = 'rgba(0,0,0,0.8)';
        this.ctx.shadowBlur = 8;
        this.ctx.fillText(text, x, y);
        this.ctx.shadowBlur = 0;
    },

    drawHUD() {
        // Score
        this.drawText(`🎯 امتیاز: ${this.score}`, 30, 50, '#ffd93d', 24);
        this.drawText(`❤️ زندگی: ${'♥'.repeat(this.lives)}`, 30, 90, '#ff6b6b', 22);
        
        // FPS
        if (this.fps) {
            this.drawText(`⚡ FPS: ${this.fps}`, this.canvas.width - 150, 50, '#88ddff', 18, 'right');
        }

        // Controls hint
        this.drawText('WASD حرکت | موس بکش برای چرخش | Space انفجار', 
            this.canvas.width / 2, this.canvas.height - 30, '#8899aa', 16, 'center');
    },

    // ==========================================
    // FPS COUNTER
    // ==========================================
    fps: 0,
    frameCount: 0,
    fpsTimer: 0,

    // ==========================================
    // MAIN GAME LOOP
    // ==========================================
    update() {
        // Camera movement
        const speed = 8;
        if (this.keys['a'] || this.keys['arrowleft']) this.camera.x -= speed;
        if (this.keys['d'] || this.keys['arrowright']) this.camera.x += speed;
        if (this.keys['w'] || this.keys['arrowup']) {
            this.camera.z -= speed;
            this.camera.y -= 0.5;
        }
        if (this.keys['s'] || this.keys['arrowdown']) {
            this.camera.z += speed;
            this.camera.y += 0.5;
        }
        this.camera.y = Math.max(-50, Math.min(50, this.camera.y));

        // Auto-rotate objects
        for (const obj of this.objects) {
            if (obj.type !== 'line' && obj.id !== 'grid') {
                obj.rotY += 0.008;
                obj.rotX += 0.004;
                // Floating animation
                if (obj.floatOffset !== undefined) {
                    obj.y += Math.sin(Date.now() / 1000 * obj.floatSpeed + obj.floatOffset) * 0.05;
                }
            }
        }

        // Update particles
        this.particles = this.particles.filter(p => {
            p.x += p.vx * 0.1;
            p.y += p.vy * 0.1;
            p.z += p.vz * 0.1;
            p.vy += p.gravity;
            p.life--;
            p.size *= 0.97;
            return p.life > 0 && p.size > 0.5;
        });

        // Physics
        this.updatePhysics();
        this.checkCollisions();

        // FPS counter
        this.frameCount++;
        this.fpsTimer += 0.016;
        if (this.fpsTimer >= 1) {
            this.fps = this.frameCount;
            this.frameCount = 0;
            this.fpsTimer = 0;
        }
    },

    render() {
        const ctx = this.ctx;
        const { width, height } = this.canvas;

        // Background gradient
        const grad = ctx.createRadialGradient(width/2, height/2-50, 50, width/2, height/2, 600);
        grad.addColorStop(0, '#1a0a2e');
        grad.addColorStop(0.5, '#0d0d2b');
        grad.addColorStop(1, '#050510');
        ctx.fillStyle = grad;
        ctx.fillRect(0, 0, width, height);

        // Draw all 3D objects
        const sorted = [...this.objects].sort((a, b) => {
            const distA = (a.x - this.camera.x)**2 + (a.y - this.camera.y)**2 + (a.z - this.camera.z)**2;
            const distB = (b.x - this.camera.x)**2 + (b.y - this.camera.y)**2 + (b.z - this.camera.z)**2;
            return distB - distA;
        });

        for (const obj of sorted) {
            if (!obj.active) continue;
            this.drawObject3D(obj);
        }

        // Draw particles (3D projection)
        for (const p of this.particles) {
            const pos = this.project(p.x, p.y, p.z);
            const size = p.size * pos.scale;
            if (size < 0.5 || pos.depth < 0) continue;
            
            ctx.globalAlpha = Math.min(1, (p.life / p.maxLife) * 1.2);
            ctx.fillStyle = p.color;
            ctx.shadowColor = p.color;
            ctx.shadowBlur = 15;
            ctx.beginPath();
            ctx.arc(pos.x, pos.y, Math.max(1, size), 0, Math.PI * 2);
            ctx.fill();
            ctx.shadowBlur = 0;
        }
        ctx.globalAlpha = 1;

        // HUD
        this.drawHUD();
    },

    gameLoop() {
        this.update();
        this.render();
        requestAnimationFrame(() => this.gameLoop());
    },

    // ==========================================
    // UTILITY FUNCTIONS
    // ==========================================
    addScore(points) {
        this.score += points;
        this.playSound(500 + points * 20, 0.15);
    },

    resetGame() {
        this.score = 0;
        this.lives = 3;
        this.particles = [];
        this.objects = [];
        this.createDefaultScene();
        this.camera = { x: 0, y: 0, z: 380, rotX: 0.35, rotY: 0.45, fov: 580 };
        this.gameState = 'playing';
        this.playSound(880, 0.3, 'square');
        console.log('🔄 Game Reset!');
    },

    // ==========================================
    // EXPORT DEMO
    // ==========================================
    runDemo() {
        this.init();
        // Spawn some initial particles
        setTimeout(() => this.spawnExplosion(0, 20, 0, 80), 500);
        setTimeout(() => this.spawnExplosion(-50, 50, -50, 60), 1000);
        setTimeout(() => this.spawnExplosion(50, 30, 50, 60), 1500);
    }
};

// Export for browser
if (typeof window !== 'undefined') {
    window.NimaView = NimaView;
}

console.log('%c📦 NimaView Engine Ready!', 'color:#88ffaa;font-size:16px;');
console.log('%c🔧 Run NimaView.runDemo() to start demo', 'color:#aaa;font-size:13px;');